THE CLAIM:
{
 "title": "Unsourced 'Europe = 30%' hop could drop the base below its floor",
 "narrative": "The model builds tamBase from a global figure times a 'Europe = 30%' share, and presents it as a bounded 240 to 360 range. But that 30% share is an analyst guess with no source, and the global anchor itself ranges from $1.7B to $5.3B, wider than the stated band. A hostile reviewer who swaps in the lowest credible numbers lands near €200M, below the floor, so the Year-1 base cannot survive audit.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Diligence checks the global anchor and finds estimates from $1.7B to $5.3B.",
   "refs": [
    "digest:cust-mix#c9",
    "digest:cust-mix#c11",
    "ledger:tamBase"
   ]
  },
  {
   "step": "propagation",
   "text": "The unsourced 30% Europe share cannot rescue a contested anchor.",
   "refs": [
    "ledger:tamBase",
    "digest:geo-region-denominator#c5",
    "digest:geo-region-denominator#c0"
   ]
  },
  {
   "step": "model-impact",
   "text": "Every downstream number inherits a base below the stated band.",
   "refs": [
    "ledger:tamBase",
    "ledger:serviceableFactor"
   ]
  }
 ],
 "falsifier": "Commissioned IndexBox EU rack-PDU country tables placing the CE-7 base at €270M or above.",
 "category": "fact",
 "evidence": [
  {
   "title": "Data Center Rack Power Distribution Unit Market Report 2033",
   "sourceType": "industry-report",
   "publisher": "Grand View Research",
   "date": "2026-02",
   "excerpt": "North America held 38.0% revenue share of the global data center rack power distribution unit market. Global market size estimated at USD 2.81 billion in 2025.",
   "url": "https://www.grandviewresearch.com/industry-analysis/data-center-rack-power-distribution-unit-pdu-market",
   "attached": true
  },
  {
   "title": "Data Center Rack PDU - Global Market Share and Ranking, Forecast 2024-2030",
   "sourceType": "analyst-estimate",
   "publisher": "QY Research",
   "date": "2025-01-02",
   "excerpt": "The global market for Data Center Rack Power Distribution Unit (PDU) was estimated to be worth US$ 1582 million in 2023, far below other publishers' figures.",
   "url": "https://www.qyresearch.com/reports/3520535/data-center-rack-power-distribution-unit--pdu",
   "attached": true
  },
  {
   "title": "Power Distribution Unit Market Size ($8.5 Billion) 2030",
   "sourceType": "analyst-estimate",
   "publisher": "Strategic Market Research",
   "date": null,
   "excerpt": "The Power Distribution Unit (PDU) Market was valued at USD 4.8 billion in 2024 and is projected to reach around USD 8.5 billion by 2030.",
   "url": "https://www.strategicmarketresearch.com/market-report/power-distribution-unit-market",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "tamBase",
  "label": "Central Europe rack-PDU market, all segments/buyers",
  "kind": "estimated",
  "value": 300,
  "unit": "EUR_M",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 240,
   "high": 360
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down scope-down from the global rack-PDU base",
   "expression": "Global rack-PDU $2.81B (Grand View, 2025) × Europe ≈ 30% [est.; NA = 38% per same source] ≈ $843M ≈ €775M @0.92 (Jul 2026) × CE-7 = 39.8% of Europe colo MW (Statista 2025) ≈ €310M → curated €300M",
   "crossCheck": "Refinement cycle 1: the prior €495M ceiling (BIS/R&M €2.45B) measures PDUs+PSUs combined — a broader category growing 21% CAGR vs intelligent-PDU 10–12% (IndexBox). Contaminated ceiling removed; band top lowered to €360M."
  },
  "provenance": {
   "rationale": "No public Europe- or CE-scoped rack-PDU figure exists; the scope-down chain anchors the value, and refinement cycle 1 killed the inflated PDUs+PSUs cross-check ceiling.",
   "promotionPath": "Commission the IndexBox EU Rack PDUs report (country tables) to pin the EU base directly."
  },
  "evidence": [
   {
    "title": "Data Center Rack PDU Market Size | Industry Report, 2033",
    "sourceType": "industry-report",
    "publisher": "Grand View Research",
    "date": "2025",
    "excerpt": "The global data center rack power distribution unit market size was estimated at USD 2.81 billion in 2025 and is projected to reach USD 5.87 billion by 2033... North America held 38.0% revenue share.",
    "attached": true
   },
   {
    "title": "Europe Data Center PDUs and PSUs Market 2025–2035",
    "sourceType": "industry-report",
    "publisher": "Research and Markets / BIS Research",
    "date": "2025",
    "excerpt": "The Europe data center PDUs and PSUs market is projected to reach $20.05 billion by 2035 from $2.45 billion in 2024 — a broader category (PDUs + PSUs) used as the cross-check ceiling.",
    "attached": true
   },
   {
    "title": "IndexBox — Rack PDUs Market in the European Union (country tables)",
    "sourceType": "pending",
    "publisher": "IndexBox",
    "date": null,
    "excerpt": "The directly-scoped EU rack-PDU report exists but its headline figure is paywalled — commissioning it would collapse the ±40% band.",
    "attached": false
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
